using System;using System.Collections.Generic;using System.Windows.Data;using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.DataBinding{    /// <summary>    /// 数据绑定管理器    /// </summary>    public class DataBindingManager    {        private readonly DesignContext _context;        private readonly List<IDataSource> _dataSources = new List<IDataSource>();                /// <summary>        /// 数据源集合        /// </summary>        public IReadOnlyList<IDataSource> DataSources => _dataSources.AsReadOnly();                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public DataBindingManager(DesignContext context)        {            _context = context;        }                /// <summary>        /// 添加数据源        /// </summary>        /// <param name="dataSource">数据源</param>        public void AddDataSource(IDataSource dataSource)        {            if (dataSource != null && !_dataSources.Contains(dataSource))            {                _dataSources.Add(dataSource);            }        }                /// <summary>        /// 移除数据源        /// </summary>        /// <param name="dataSource">数据源</param>        public void RemoveDataSource(IDataSource dataSource)        {            if (dataSource != null && _dataSources.Contains(dataSource))            {                if (dataSource.IsConnected)                {                    dataSource.Disconnect();                }                _dataSources.Remove(dataSource);            }        }                /// <summary>        /// 绑定属性        /// </summary>        /// <param name="item">设计项</param>        /// <param name="propertyName">属性名</param>        /// <param name="bindingPath">绑定路径</param>        /// <param name="mode">绑定模式</param>        public void BindProperty(DesignItem item, string propertyName, string bindingPath, BindingMode mode = BindingMode.TwoWay)        {            if (item == null || string.IsNullOrEmpty(propertyName) || string.IsNullOrEmpty(bindingPath))                return;                        try            {                var property = item.Properties.GetProperty(propertyName);                if (property != null)                {                    // 创建绑定                    var binding = new Binding(bindingPath)                    {                        Mode = mode,                        UpdateSourceTrigger = UpdateSourceTrigger.PropertyChanged                    };                                        // 应用绑定                    property.SetValue(binding);                }            }            catch (Exception ex)            {                Console.WriteLine($"绑定属性失败: {ex.Message}");            }        }                /// <summary>        /// 绑定属性到数据源        /// </summary>        /// <param name="item">设计项</param>        /// <param name="propertyName">属性名</param>        /// <param name="dataSource">数据源</param>        /// <param name="dataPath">数据路径</param>        /// <param name="mode">绑定模式</param>        public void BindToDataSource(DesignItem item, string propertyName, IDataSource dataSource, string dataPath, BindingMode mode = BindingMode.TwoWay)        {            if (item == null || string.IsNullOrEmpty(propertyName) || dataSource == null || string.IsNullOrEmpty(dataPath))                return;                        try            {                // 确保数据源已连接                if (!dataSource.IsConnected)                {                    dataSource.Connect();                }                                // 创建绑定                var binding = new Binding(dataPath)                {                    Mode = mode,                    UpdateSourceTrigger = UpdateSourceTrigger.PropertyChanged,                    Source = dataSource.GetData(dataPath)                };                                // 应用绑定                var property = item.Properties.GetProperty(propertyName);                if (property != null)                {                    property.SetValue(binding);                }            }            catch (Exception ex)            {                Console.WriteLine($"绑定到数据源失败: {ex.Message}");            }        }                /// <summary>        /// 清除属性绑定        /// </summary>        /// <param name="item">设计项</param>        /// <param name="propertyName">属性名</param>        public void ClearBinding(DesignItem item, string propertyName)        {            if (item == null || string.IsNullOrEmpty(propertyName))                return;                        try            {                var property = item.Properties.GetProperty(propertyName);                if (property != null)                {                    property.ClearValue();                }            }            catch (Exception ex)            {                Console.WriteLine($"清除绑定失败: {ex.Message}");            }        }                /// <summary>        /// 获取绑定表达式        /// </summary>        /// <param name="item">设计项</param>        /// <param name="propertyName">属性名</param>        /// <returns>绑定表达式</returns>        public BindingBase GetBinding(DesignItem item, string propertyName)        {            if (item == null || string.IsNullOrEmpty(propertyName))                return null;                        try            {                var property = item.Properties.GetProperty(propertyName);                if (property != null)                {                    return property.Value as BindingBase;                }            }            catch (Exception ex)            {                Console.WriteLine($"获取绑定表达式失败: {ex.Message}");            }                        return null;        }